1	// QEMU TCG plugin: drains architectural state and exits when the guest
2	// executes `csrwi 0x7C0, 0`. Shares hybrid/insn_match.h and
3	// hybrid/state_abi.h with the vsim side.
4	
5	#include "hybrid/insn_match.h"
6	#include "hybrid/state_abi.h"
7	
8	#include <qemu-plugin.h>
9	
10	#include <glib.h>
11	
12	#include <fcntl.h>
13	#include <stddef.h>
14	#include <stdint.h>
15	#include <stdio.h>
16	#include <stdlib.h>
17	#include <string.h>
18	#include <unistd.h>
19	#include <limits.h>
20	
21	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
22	
23	typedef struct {
24	    struct qemu_plugin_register *gpr[32];
25	    struct qemu_plugin_register *pc;
26	} VcpuRegs;
27	
28	static struct qemu_plugin_scoreboard *vcpu_state;
29	static char *outfile_path;
30	
31	// GPR ABI names as exposed by QEMU's RISC-V gdbstub; index = x register index.
32	static const char *const gpr_names[32] = {
33	    "zero", "ra",  "sp",  "gp",  "tp",  "t0", "t1", "t2",
34	    "s0",   "s1",  "a0",  "a1",  "a2",  "a3", "a4", "a5",
35	    "a6",   "a7",  "s2",  "s3",  "s4",  "s5", "s6", "s7",
36	    "s8",   "s9",  "s10", "s11", "t3",  "t4", "t5", "t6",
37	};
38	
39	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
40	{
41	    for (guint i = 0; i < regs->len; i++) {
42	        qemu_plugin_reg_descriptor *rd =
43	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
44	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
45	            return rd->handle;
46	        }
47	    }
48	    return NULL;
49	}
50	
51	static void vcpu_init(qemu_plugin_id_t id, unsigned int vcpu_idx)
52	{
53	    (void) id;
54	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
55	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
56	    for (int i = 0; i < 32; i++) {
57	        v->gpr[i] = find_reg(regs, gpr_names[i]);
58	    }
59	    v->pc = find_reg(regs, "pc");
60	}
61	
62	static uint64_t read_reg64(struct qemu_plugin_register *h)
63	{
64	    if (!h) return 0;
65	    g_autoptr(GByteArray) buf = g_byte_array_new();
66	    int sz = qemu_plugin_read_register(h, buf);
67	    if (sz <= 0) return 0;
68	    uint64_t v = 0;
69	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
70	    return v;
71	}
72	
73	// Atomic on POSIX: write to .tmp, fsync, rename.
74	static int write_state_atomic(const struct hybrid_state_v1 *s, const char *path)
75	{
76	    char tmp[PATH_MAX];
77	    g_snprintf(tmp, sizeof(tmp), "%s.tmp.%d", path, (int) getpid());
78	    int fd = open(tmp, O_WRONLY | O_CREAT | O_TRUNC, 0600);
79	    if (fd < 0) {
80	        perror("hybrid_handoff: open tmp");
81	        return -1;
82	    }
83	    ssize_t want = (ssize_t) sizeof(*s);
84	    ssize_t got = write(fd, s, sizeof(*s));
85	    if (got != want) {
86	        perror("hybrid_handoff: write");
87	        close(fd);
88	        unlink(tmp);
89	        return -1;
90	    }
91	    fsync(fd);
92	    close(fd);
93	    if (rename(tmp, path) != 0) {
94	        perror("hybrid_handoff: rename");
95	        unlink(tmp);
96	        return -1;
97	    }
98	    return 0;
99	}
100	
101	static void on_handoff(unsigned int vcpu_idx, void *udata)
102	{
103	    hybrid_handoff_kind kind = (hybrid_handoff_kind) (uintptr_t) udata;
104	    if (kind != HYBRID_HANDOFF_ENTER) return;
105	
106	    VcpuRegs *v = qemu_plugin_scoreboard_find(vcpu_state, vcpu_idx);
107	    struct hybrid_state_v1 s = {0};
108	    s.magic   = HYBRID_STATE_MAGIC;
109	    s.version = HYBRID_STATE_VERSION;
110	    s.flags   = HYBRID_FLAG_RV64;
111	    s.hart_id = vcpu_idx;
112	    s.priv    = 3;
113	    s.pc      = read_reg64(v->pc);
114	    for (int i = 0; i < 32; i++) s.gpr[i] = read_reg64(v->gpr[i]);
115	
116	    if (write_state_atomic(&s, outfile_path) != 0) {
117	        fprintf(stderr, "hybrid_handoff: failed to write state file\n");
118	        exit(2);
119	    }
120	    fprintf(stderr,
121	            "hybrid_handoff: drained state to %s (pc=%#" PRIx64 "), exiting\n",
122	            outfile_path, s.pc);
123	    exit(0);
124	}
125	
126	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
127	{
128	    (void) id;
129	    size_t n = qemu_plugin_tb_n_insns(tb);
130	    for (size_t i = 0; i < n; i++) {
131	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
132	        size_t sz = qemu_plugin_insn_size(insn);
133	        if (sz != 4) continue;
134	        uint32_t raw = 0;
135	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
136	            continue;
137	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
138	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
139	        qemu_plugin_register_vcpu_insn_exec_cb(
140	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
141	            (void *) (uintptr_t) kind);
142	    }
143	}
144	
145	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
146	                                           const qemu_info_t *info,
147	                                           int argc, char **argv)
148	{
149	    (void) info;
150	    for (int i = 0; i < argc; i++) {
151	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
152	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
153	            outfile_path = g_strdup(tok[1]);
154	        } else {
155	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
156	            return -1;
157	        }
158	    }
159	    if (!outfile_path) {
160	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
161	        return -1;
162	    }
163	
164	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
165	    qemu_plugin_register_vcpu_init_cb(id, vcpu_init);
166	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
167	    return 0;
168	}
