1	// Wire contract between the QEMU TCG plugin and vsim. Both sides write/read
2	// `struct hybrid_state_v1` byte-for-byte through a shared file.
3	//
4	// Stability: never repurpose offsets within a published version. Add new
5	// fields by consuming bytes from `reserved`, or by introducing v2 alongside.
6	//
7	// C and C++ both compile this header.
8	
9	#ifndef HYBRID_STATE_ABI_H
10	#define HYBRID_STATE_ABI_H
11	
12	#include <stdint.h>
13	#include <stddef.h>
14	
15	#ifdef __cplusplus
16	extern "C" {
17	#endif
18	
19	#define HYBRID_STATE_MAGIC   0x42594841u  // 'AHYB' little-endian
20	#define HYBRID_STATE_VERSION 1u
21	
22	#define HYBRID_FLAG_RV64 (1u << 0)
23	#define HYBRID_FLAG_FP   (1u << 1)
24	#define HYBRID_FLAG_V    (1u << 2)
25	
26	// 1024-bit VLEN upper bound: covers all AX45MPV configurations.
27	#define HYBRID_VLEN_BYTES_MAX 128
28	
29	// 64 PMP entries; pmpcfg slots reserved at 16 so the layout works for both
30	// RV64 (8 entries/CSR) and a future RV32 (4 entries/CSR) packing.
31	#define HYBRID_PMP_CFG_NUM  16
32	#define HYBRID_PMP_ADDR_NUM 64
33	
34	// All fields are naturally 8-byte aligned, so __attribute__((packed)) is
35	// unnecessary and would force unaligned access codegen. Layout is locked by
36	// the static_asserts in state_abi_check.h.
37	struct hybrid_state_v1 {
38	  uint32_t magic;
39	  uint32_t version;
40	  uint32_t flags;
41	  uint32_t hart_id;
42	  uint64_t pc;
43	  uint64_t priv;  // 0=U, 1=S, 3=M
44	
45	  uint64_t gpr[32];
46	  uint64_t fpr[32];
47	
48	  uint64_t mstatus;
49	  uint64_t mepc;
50	  uint64_t mtvec;
51	  uint64_t mcause;
52	  uint64_t mtval;
53	  uint64_t mscratch;
54	  uint64_t medeleg;
55	  uint64_t mideleg;
56	  uint64_t mip;
57	  uint64_t mie;
58	  uint64_t mcycle;
59	  uint64_t minstret;
60	  uint64_t satp;
61	
62	  uint64_t pmpcfg[HYBRID_PMP_CFG_NUM];
63	  uint64_t pmpaddr[HYBRID_PMP_ADDR_NUM];
64	
65	  uint64_t vstart;
66	  uint64_t vtype;
67	  uint64_t vl;
68	  uint64_t vlenb;
69	  uint8_t  vreg[32 * HYBRID_VLEN_BYTES_MAX];
70	
71	  uint8_t  reserved[256];  // zero-initialise on write
72	};
73	
74	#ifdef __cplusplus
75	}  // extern "C"
76	#endif
77	
78	#include "hybrid/state_abi_check.h"
79	
80	#endif  // HYBRID_STATE_ABI_H
81

1	// Compile-time layout lock for hybrid_state_v1. The ABI is a wire contract,
2	// so any offset or size drift must break every consumer at compile time.
3	
4	#ifndef HYBRID_STATE_ABI_CHECK_H
5	#define HYBRID_STATE_ABI_CHECK_H
6	
7	#include "hybrid/state_abi.h"
8	
9	// C++20 has static_assert; C11+ has _Static_assert. Pick the one that exists.
10	#ifndef __cplusplus
11	#  define static_assert _Static_assert
12	#endif
13	
14	static_assert(offsetof(struct hybrid_state_v1, magic)    == 0,    "magic@0");
15	static_assert(offsetof(struct hybrid_state_v1, version)  == 4,    "version@4");
16	static_assert(offsetof(struct hybrid_state_v1, flags)    == 8,    "flags@8");
17	static_assert(offsetof(struct hybrid_state_v1, hart_id)  == 12,   "hart_id@12");
18	static_assert(offsetof(struct hybrid_state_v1, pc)       == 16,   "pc@16");
19	static_assert(offsetof(struct hybrid_state_v1, priv)     == 24,   "priv@24");
20	
21	static_assert(offsetof(struct hybrid_state_v1, gpr)      == 32,   "gpr@32");
22	static_assert(offsetof(struct hybrid_state_v1, fpr)      == 288,  "fpr@288");
23	
24	static_assert(offsetof(struct hybrid_state_v1, mstatus)  == 544,  "mstatus@544");
25	static_assert(offsetof(struct hybrid_state_v1, mepc)     == 552,  "mepc@552");
26	static_assert(offsetof(struct hybrid_state_v1, mtvec)    == 560,  "mtvec@560");
27	static_assert(offsetof(struct hybrid_state_v1, mcause)   == 568,  "mcause@568");
28	static_assert(offsetof(struct hybrid_state_v1, mtval)    == 576,  "mtval@576");
29	static_assert(offsetof(struct hybrid_state_v1, mscratch) == 584,  "mscratch@584");
30	static_assert(offsetof(struct hybrid_state_v1, medeleg)  == 592,  "medeleg@592");
31	static_assert(offsetof(struct hybrid_state_v1, mideleg)  == 600,  "mideleg@600");
32	static_assert(offsetof(struct hybrid_state_v1, mip)      == 608,  "mip@608");
33	static_assert(offsetof(struct hybrid_state_v1, mie)      == 616,  "mie@616");
34	static_assert(offsetof(struct hybrid_state_v1, mcycle)   == 624,  "mcycle@624");
35	static_assert(offsetof(struct hybrid_state_v1, minstret) == 632,  "minstret@632");
36	static_assert(offsetof(struct hybrid_state_v1, satp)     == 640,  "satp@640");
37	
38	static_assert(offsetof(struct hybrid_state_v1, pmpcfg)   == 648,  "pmpcfg@648");
39	static_assert(offsetof(struct hybrid_state_v1, pmpaddr)  == 776,  "pmpaddr@776");
40	
41	static_assert(offsetof(struct hybrid_state_v1, vstart)   == 1288, "vstart@1288");
42	static_assert(offsetof(struct hybrid_state_v1, vtype)    == 1296, "vtype@1296");
43	static_assert(offsetof(struct hybrid_state_v1, vl)       == 1304, "vl@1304");
44	static_assert(offsetof(struct hybrid_state_v1, vlenb)    == 1312, "vlenb@1312");
45	static_assert(offsetof(struct hybrid_state_v1, vreg)     == 1320, "vreg@1320");
46	
47	static_assert(offsetof(struct hybrid_state_v1, reserved) == 5416, "reserved@5416");
48	static_assert(sizeof(struct hybrid_state_v1) == 5672, "hybrid_state_v1 total size");
49	
50	static_assert(HYBRID_VLEN_BYTES_MAX == 128, "VLEN bytes pinned to 1024-bit");
51	static_assert(HYBRID_PMP_CFG_NUM    == 16,  "pmpcfg slot count");
52	static_assert(HYBRID_PMP_ADDR_NUM   == 64,  "pmpaddr entry count");
53	
54	#endif  // HYBRID_STATE_ABI_CHECK_H
