1	// StateDrain is the dual of ResumeDriver: halt the hart via the Debug Module,
2	// read x1..x31 + DPC via Abstract Commands, populate hybrid_state_v1.
3	
4	#include "hybrid/abstract_command.hpp"
5	#include "hybrid/resume_driver.hpp"
6	#include "hybrid/state_abi.h"
7	#include "hybrid/state_drain.hpp"
8	#include "recording_bus.hpp"
9	
10	#define DOCTEST_CONFIG_IMPLEMENT_WITH_MAIN
11	#include <doctest.h>
12	
13	#include <cstdint>
14	
15	using hybrid::test::DmiOp;
16	using hybrid::test::kDmstatusHaltedAndAcked;
17	using hybrid::test::RecordingBus;
18	using RD = hybrid::ResumeDriver;
19	
20	TEST_CASE("state_drain primes dmactive then issues haltreq before any read")
21	{
22	  RecordingBus bus;
23	  bus.dmstatus_value = kDmstatusHaltedAndAcked;
24	
25	  hybrid::StateDrain drain(bus);
26	  (void) drain.drain();
27	
28	  REQUIRE(bus.ops.size() >= 2);
29	  CHECK(bus.ops[0].kind == DmiOp::Kind::Write);
30	  CHECK(bus.ops[0].reg == RD::kDmcontrol);
31	  CHECK((bus.ops[0].value & RD::kDmcontrolDmactive) != 0u);
32	  CHECK((bus.ops[0].value & RD::kDmcontrolHaltreq) == 0u);
33	
34	  CHECK(bus.ops[1].kind == DmiOp::Kind::Write);
35	  CHECK(bus.ops[1].reg == RD::kDmcontrol);
36	  CHECK((bus.ops[1].value & RD::kDmcontrolDmactive) != 0u);
37	  CHECK((bus.ops[1].value & RD::kDmcontrolHaltreq) != 0u);
38	}
39	
40	TEST_CASE("state_drain reads x1..x31 via Abstract Commands, skipping x0")
41	{
42	  RecordingBus bus;
43	  bus.dmstatus_value = kDmstatusHaltedAndAcked;
44	  for (uint16_t i = 0; i < 32; ++i)
45	    bus.regfile[hybrid::regno_gpr(i)] = 0xa00000000ULL + i;
46	
47	  hybrid::StateDrain drain(bus);
48	  const auto state = drain.drain();
49	
50	  for (int i = 1; i < 32; ++i) {
51	    CHECK(state.gpr[i] == 0xa00000000ULL + i);
52	  }
53	  for (const auto& op : bus.ops) {
54	    if (op.kind == DmiOp::Kind::Write && op.reg == RD::kCommand) {
55	      const uint16_t regno = op.value & 0xffffu;
56	      CHECK(regno != hybrid::regno_gpr(0));
57	    }
58	  }
59	}
60	
61	TEST_CASE("state_drain captures pc from DPC")
62	{
63	  RecordingBus bus;
64	  bus.dmstatus_value = kDmstatusHaltedAndAcked;
65	  bus.regfile[hybrid::regno_csr(RD::kCsrDpc)] = 0x12345678'9ABCDEF0ULL;
66	
67	  hybrid::StateDrain drain(bus);
68	  const auto state = drain.drain();
69	
70	  CHECK(state.pc == 0x12345678'9ABCDEF0ULL);
71	}
72	
73	TEST_CASE("state_drain populates header fields (magic, version, flags)")
74	{
75	  RecordingBus bus;
76	  bus.dmstatus_value = kDmstatusHaltedAndAcked;
77	
78	  hybrid::StateDrain drain(bus);
79	  const auto state = drain.drain();
80	
81	  CHECK(state.magic == HYBRID_STATE_MAGIC);
82	  CHECK(state.version == HYBRID_STATE_VERSION);
83	  CHECK((state.flags & HYBRID_FLAG_RV64) != 0u);
84	}
85	
86	TEST_CASE("state_drain issues a COMMAND read for each x1..x31 + DPC")
87	{
88	  RecordingBus bus;
89	  bus.dmstatus_value = kDmstatusHaltedAndAcked;
90	
91	  hybrid::StateDrain drain(bus);
92	  (void) drain.drain();
93	
